const topic = $.input.topic;
const style = $.input.style || 'POV storytelling';
const duration = $.input.duration || '30-60 seconds';
const today = new Date().toISOString().split('T')[0];

let prompt = 'You are an expert short-form video creator specializing in viral content for TikTok, YouTube Shorts, and Instagram Reels.\n\n';
prompt += 'Create a complete video production script for the following:\n';
prompt += '- Topic: ' + topic + '\n';
prompt += '- Style: ' + style + '\n';
prompt += '- Duration: ' + duration + '\n\n';
prompt += 'INSTRUCTIONS:\n';
prompt += '- Create a viral hook that stops scrolling in the first 2 seconds\n';
prompt += '- Write scene-by-scene breakdown with timing\n';
prompt += '- For each scene, provide a detailed AI image generation prompt (Flux/DALL-E style)\n';
prompt += '- Write the complete voiceover script with emotion cues\n';
prompt += '- Include transitions and visual effects suggestions\n';
prompt += '- Write platform-optimized captions and hashtags\n\n';
prompt += 'Return ONLY valid JSON:\n';
prompt += '{\n';
prompt += '  "title": "video title",\n';
prompt += '  "hook": "first 2-second hook text",\n';
prompt += '  "style": "' + style + '",\n';
prompt += '  "totalDuration": "estimated duration",\n';
prompt += '  "scenes": [\n';
prompt += '    {\n';
prompt += '      "sceneNum": 1,\n';
prompt += '      "duration": "3s",\n';
prompt += '      "visualDescription": "what the viewer sees",\n';
prompt += '      "aiImagePrompt": "detailed prompt for Flux/DALL-E image generation",\n';
prompt += '      "voiceover": "what is said",\n';
prompt += '      "emotionCue": "excited/calm/dramatic",\n';
prompt += '      "transition": "cut/zoom/fade"\n';
prompt += '    }\n';
prompt += '  ],\n';
prompt += '  "fullVoiceover": "complete voiceover script concatenated",\n';
prompt += '  "musicSuggestion": "music style and mood",\n';
prompt += '  "soundEffects": ["effect 1", "effect 2"],\n';
prompt += '  "caption": "social media caption",\n';
prompt += '  "hashtags": ["#tag1", "#tag2"],\n';
prompt += '  "platformNotes": { "tiktok": "tip", "youtube": "tip", "instagram": "tip" }\n';
prompt += '}';

return { prompt, today, topic, style };

let raw = $.steps.aiGenerate.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { title: 'Video Script', hook: '', scenes: [], fullVoiceover: raw, caption: '', hashtags: [] }; }

const ai = $.steps.parseAI.output;
const today = $.steps.buildPrompt.output.today;

let sceneList = '';
(ai.scenes || []).forEach(s => {
  sceneList += '**Scene ' + s.sceneNum + '** (' + (s.duration || '') + '): ' + (s.visualDescription || '') + '\n';
});

const embeds = [{
  title: ai.title || 'Video Script',
  description: '**Hook:** ' + (ai.hook || '') + '\n\n**Scenes:**\n' + sceneList.slice(0, 1500) + '\n\n**Voiceover:**\n' + (ai.fullVoiceover || '').slice(0, 500),
  color: 16744448,
  fields: [
    { name: 'Style', value: ai.style || 'N/A', inline: true },
    { name: 'Duration', value: ai.totalDuration || 'N/A', inline: true },
    { name: 'Music', value: ai.musicSuggestion || 'N/A', inline: true }
  ],
  footer: { text: 'Short-Form Video Generator | ' + today }
}];

const contentText = 'New Short-Form Video Script: **' + (ai.title || 'Untitled') + '** ' + (ai.hashtags || []).join(' ');
return { content: contentText.slice(0, 2000), embeds };

const ai = $.steps.parseAI.output;
const today = $.steps.buildPrompt.output.today;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: ai.title || 'Video Script', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Style:*\n' + (ai.style || 'N/A') },
  { type: 'mrkdwn', text: '*Duration:*\n' + (ai.totalDuration || 'N/A') },
  { type: 'mrkdwn', text: '*Music:*\n' + (ai.musicSuggestion || 'N/A') }
] });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Hook:*\n' + (ai.hook || 'N/A') } });
blocks.push({ type: 'divider' });

let scenesText = '*Scene Breakdown:*\n';
(ai.scenes || []).forEach(s => {
  scenesText += '*Scene ' + s.sceneNum + '* (' + (s.duration || '') + '): ' + (s.visualDescription || '') + '\n';
  scenesText += '_Voiceover: ' + (s.voiceover || '') + '_\n';
  scenesText += 'Transition: ' + (s.transition || 'cut') + '\n\n';
});
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: scenesText.slice(0, 1800) } });
blocks.push({ type: 'divider' });

let imagePrompts = '*AI Image Prompts:*\n';
(ai.scenes || []).forEach(s => {
  if (s.aiImagePrompt) imagePrompts += '*Scene ' + s.sceneNum + ':* ' + s.aiImagePrompt + '\n\n';
});
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: imagePrompts.slice(0, 1800) } });
blocks.push({ type: 'divider' });

blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Caption:*\n' + (ai.caption || '') + '\n\n' + (ai.hashtags || []).join(' ') } });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Powered by Claude AI | One CLI' }] });

const fallbackText = 'Video Script: ' + (ai.title || 'Untitled') + ' - ' + (ai.scenes || []).length + ' scenes';
return { blocks, fallbackText };
